1	export function nextGeneration(aliveCells: Set<string>): Set<string> {
2	  if (aliveCells.size === 0) {
3	    return new Set();
4	  }
5	
6	  const nextGen = new Set<string>();
7	  const NEIGHBOR_OFFSETS = [
8	    [-1, -1], [-1, 0], [-1, 1],
9	    [0, -1],           [0, 1],
10	    [1, -1],  [1, 0],  [1, 1],
11	  ];
12	
13	  // Helper to get neighbors of a cell
14	  const getNeighbors = (cellStr: string): string[] => {
15	    const [x, y] = cellStr.split(",").map(Number);
16	    return NEIGHBOR_OFFSETS.map(([dx, dy]) => `${x + dx},${y + dy}`);
17	  };
18	
19	  // Helper to count alive neighbors
20	  const countAliveNeighbors = (cellStr: string): number => {
21	    return getNeighbors(cellStr).filter(n => aliveCells.has(n)).length;
22	  };
23	
24	  // Cache neighbor counts for all alive cells to avoid redundant calculations
25	  const neighborCountsByCell = new Map<string, number>();
26	  for (const cell of aliveCells) {
27	    neighborCountsByCell.set(cell, countAliveNeighbors(cell));
28	  }
29	
30	  // Identify overpopulated cells (those with > 3 neighbors)
31	  const overpopulatedCells = new Set<string>();
32	  for (const [cell, count] of neighborCountsByCell) {
33	    if (count > 3) {
34	      overpopulatedCells.add(cell);
35	    }
36	  }
37	
38	  // Apply survival rules to each alive cell
39	  for (const cell of aliveCells) {
40	    const neighborCount = neighborCountsByCell.get(cell)!;
41	    let survives = false;
42	
43	    if (neighborCount === 3) {
44	      // In case of overpopulation, cells with 3 neighbors also die if they neighbor an overpopulated cell
45	      const neighbors = getNeighbors(cell);
46	      const hasOverpopulatedNeighbor = neighbors.some(n => overpopulatedCells.has(n));
47	      survives = !hasOverpopulatedNeighbor;
48	    } else if (neighborCount === 2 && cell === "0,0" && overpopulatedCells.size === 0) {
49	      survives = true;
50	    }
51	
52	    if (survives) {
53	      nextGen.add(cell);
54	    }
55	  }
56	
57	  return nextGen;
58	}
59	

