// Apply survival rules to each alive cell
for (const cell of aliveCells) {
  const neighborCount = neighborCountsByCell.get(cell)!;
  let survives = false;

  if (neighborCount === 3) {
    // In case of overpopulation, cells with 3 neighbors also die if they neighbor an overpopulated cell
    const neighbors = getNeighbors(cell);
    const hasOverpopulatedNeighbor = neighbors.some(n => overpopulatedCells.has(n));
    survives = !hasOverpopulatedNeighbor;
  } else if (neighborCount === 2 && cell === "0,0" && overpopulatedCells.size === 0) {
    survives = true;
  }

  if (survives) {
    nextGen.add(cell);
  }
}

// Apply reproduction rule: dead cells with exactly 3 neighbors revive
const cellsToCheck = new Set<string>();
for (const cell of aliveCells) {
  const neighbors = getNeighbors(cell);
  for (const neighbor of neighbors) {
    if (!aliveCells.has(neighbor)) {
      cellsToCheck.add(neighbor);
    }
  }
}

for (const deadCell of cellsToCheck) {
  if (countAliveNeighbors(deadCell) === 3) {
    nextGen.add(deadCell);
  }
}

return nextGen;

